<script setup>
import { computed } from 'vue';
import { formatUrl } from '../utils/formatUrl.js';

const props = defineProps({
  link: {
    type: Object,
    required: true,
  },
  isActive: {
    type: Boolean,
    default: false,
  },
  isFocused: {
    type: Boolean,
    default: false,
  },
});

/**
 * Computed property to ensure the URL is properly formatted
 * @returns {string} The properly formatted URL
 */
const formattedUrl = computed(() => formatUrl(props.link?.url));
</script>

<template>
  <a
    :href="formattedUrl"
    :id="link.id"
    class="flex flex-row rounded-lg items-center cursor-pointer gap-1 group transition-all relative border border-transparent"
    :class="
      isActive || isFocused
        ? 'text-zinc-900 dark:text-zinc-100 active bg-zinc-100 dark:bg-zinc-800/40 active'
        : 'hover:bg-zinc-100 hover:dark:bg-zinc-800/60'
    "
    :target="link.settings?.open_new ? '_BLANK' : ''"
  >
    <slot />
  </a>
</template>
