<script setup>
import { computed, watch, onUnmounted, ref } from 'vue';
import MenuItemLink from './MenuItemLink.vue';
import MenuIcon from './MenuIcon.vue';
import MenuItemName from './MenuItemName.vue';
import SubMenu from './SubMenu.vue';
import SubMenuItem from './SubMenuItem.vue';
import AppIcon from '@/components/utility/icons/index.vue';

// Store
import { useAppStore } from '@/store/app/app.js';
const appStore = useAppStore();

// Composables
import { useFavorites } from '../composables/useFavorites.js';
import { useHoverStates } from '../composables/useHoverStates.js';
import { useMenuState } from '../composables/useMenuState.js';
import { useSubmenuIntent } from '../composables/useSubmenuIntent.js';

const { favorites, addFavorite, isFavorite } = useFavorites();
const { setHoverState, isHovered, clearHoverStates } = useHoverStates();
const { isActive, shouldShowSubMenu, toggleMenuOpen } = useMenuState();
const {
  onParentEnter,
  onParentLeave,
  onSubmenuEnter,
  onSubmenuLeave,
  shouldDelaySubmenuSwitch,
  clearAllIntentState,
} = useSubmenuIntent();
const HOVER_SCOPE = 'expanded';

const props = defineProps({
  menuItems: {
    type: Array,
    required: true,
  },
  menupanel: {
    type: Object,
    default: null,
  },
  mobile: {
    type: Boolean,
    default: false,
  },
});

const canUseHoverSubmenus = computed(() => {
  return (
    !props.mobile && appStore.state.uixpress_settings?.submenu_style === 'hover'
  );
});

const rowRefs = new Map();
const submenuBounds = new Map();
const activeHoverLinkId = ref(null);

const setRowRef = (link, el) => {
  if (!link?.id) return;

  if (!el) {
    rowRefs.delete(link.id);
    submenuBounds.delete(link.id);
    return;
  }

  rowRefs.set(link.id, el);
};

const setSubmenuBounds = (link, rect) => {
  if (!link?.id || !rect) return;
  submenuBounds.set(link.id, rect);
};

const clearSubmenuBounds = (link) => {
  if (!link?.id) return;
  submenuBounds.delete(link.id);
};

const openHoverSubmenu = (link) => {
  if (!canUseHoverSubmenus.value) return;
  if (!link?.id) return;

  if (activeHoverLinkId.value && activeHoverLinkId.value !== link.id) {
    setHoverState({ id: activeHoverLinkId.value }, false, HOVER_SCOPE);
  }

  setHoverState(link, true, HOVER_SCOPE);
  activeHoverLinkId.value = link.id;
};

const closeHoverSubmenu = (link) => {
  if (!canUseHoverSubmenus.value) return;
  setHoverState(link, false, HOVER_SCOPE);
  if (activeHoverLinkId.value === link?.id) {
    activeHoverLinkId.value = null;
  }
};

const handleParentEnter = (link) => {
  if (!canUseHoverSubmenus.value || !link?.id) return;

  if (activeHoverLinkId.value && activeHoverLinkId.value !== link.id) {
    const activeParentRect =
      rowRefs.get(activeHoverLinkId.value)?.getBoundingClientRect() || null;
    const activeSubmenuRect =
      submenuBounds.get(activeHoverLinkId.value) || null;

    if (shouldDelaySubmenuSwitch(activeParentRect, activeSubmenuRect)) {
      return;
    }
  }

  onParentEnter(link.id, () => openHoverSubmenu(link));
};

const handleParentLeave = (link) => {
  if (!canUseHoverSubmenus.value || !link?.id) return;

  const parentRect = rowRefs.get(link.id)?.getBoundingClientRect() || null;
  const submenuRect = submenuBounds.get(link.id) || null;

  onParentLeave(link.id, {
    parentRect,
    submenuRect,
    closeNow: () => closeHoverSubmenu(link),
    closeDelayed: () => closeHoverSubmenu(link),
  });
};

const handleSubmenuEnter = (link) => {
  if (!canUseHoverSubmenus.value || !link?.id) return;
  onSubmenuEnter(link.id, () => openHoverSubmenu(link));
};

const handleSubmenuLeave = (link) => {
  if (!canUseHoverSubmenus.value || !link?.id) return;
  onSubmenuLeave(link.id, { close: () => closeHoverSubmenu(link) });
};

watch(
  canUseHoverSubmenus,
  (enabled) => {
    if (!enabled) {
      clearHoverStates(HOVER_SCOPE);
      clearAllIntentState();
      submenuBounds.clear();
      activeHoverLinkId.value = null;
    }
  },
  { immediate: true }
);

onUnmounted(() => {
  clearAllIntentState();
  rowRefs.clear();
  submenuBounds.clear();
  activeHoverLinkId.value = null;
});
</script>

<template>
  <!-- Standard expanded menu
  --
  -- Menu template for non minimised menu
  -->
  <div class="relative grow overflow-hidden flex min-h-0">
    <div
      class="flex flex-col grow gap-1 custom-scrollbar pb-16 min-h-0 overflow-auto"
      :class="!favorites.length ? 'mt-6' : ''"
    >
      <template v-for="(link, index) in menuItems" :key="link.id || index">
        <div
          v-if="link.type != 'separator'"
          @mouseenter="handleParentEnter(link)"
          @mouseleave="handleParentLeave(link)"
          class="relative group-parent"
          :ref="(el) => setRowRef(link, el)"
        >
          <MenuItemLink
            :link="link"
            :isActive="isActive(link)"
            class="p-1 pr-4 pl-1 text-zinc-700 dark:text-zinc-300 text-zinc-700 dark:text-zinc-300"
          >
            <!--Icon-->
            <div class="absolute px-4 left-0">
              <MenuIcon :link="link" />
            </div>

            <!-- Item name -->
            <MenuItemName :link="link" :active="isActive(link)" />

            <!-- Favorite icon -->
            <AppIcon
              v-if="!isFavorite(link.url)"
              icon="star"
              class="opacity-0 group-hover:opacity-100 text-base transition-opacity"
              @click.prevent.stop="addFavorite(link)"
            />

            <!-- Submenu icon (always show on mobile for tap-to-expand, or when not in hover mode) -->
            <AppIcon
              v-if="link.submenu && link.submenu.length && !canUseHoverSubmenus"
              :icon="
                isActive(link) || link.active || link.open
                  ? 'expand_more'
                  : 'chevron_left'
              "
              :class="isActive(link) ? 'opacity-100' : ''"
              class="opacity-0 max-md:opacity-100 group-hover:opacity-100 text-base transition-opacity"
              @click.prevent.stop="toggleMenuOpen(link)"
            />

            <!-- Open in new -->
            <AppIcon
              v-if="link.settings?.open_new"
              icon="open_new"
              :class="isActive(link) ? 'opacity-100' : ''"
              class="opacity-0 max-md:opacity-100 group-hover:opacity-100 text-base transition-opacity"
            />
          </MenuItemLink>

          <!-- Inline Sub menu -->
          <Transition v-if="shouldShowSubMenu(link)">
            <div class="mt-2 mb-4 pl-1">
              <template v-for="sublink in link.submenu" :key="sublink.id">
                <SubMenuItem
                  :isActive="isActive(sublink)"
                  :sublink="sublink"
                  :isFavorite="isFavorite(sublink.url)"
                  class="pl-12"
                />
              </template>
            </div>
          </Transition>

          <!-- Hover submenu -->
          <div
            v-else-if="
              link.submenu &&
              link.submenu.length &&
              isHovered(link, HOVER_SCOPE) &&
              canUseHoverSubmenus
            "
            class="absolute right-0 top-0 translate-x-full"
            :target="link.settings?.open_new ? '_BLANK' : ''"
          >
            <Transition>
              <SubMenu
                :parent="menupanel"
                :mouseenter="() => handleSubmenuEnter(link)"
                :mouseleave="() => handleSubmenuLeave(link)"
                :submenuBoundsChange="(rect) => setSubmenuBounds(link, rect)"
                :submenuUnmount="() => clearSubmenuBounds(link)"
              >
                <template v-for="sublink in link.submenu" :key="sublink.id">
                  <SubMenuItem
                    :isActive="isActive(sublink)"
                    :sublink="sublink"
                    :isFavorite="isFavorite(sublink.url)"
                    :hideFavorite="true"
                  />
                </template>
              </SubMenu>
            </Transition>
          </div>
        </div>

        <!-- Separator without name -->
        <div
          v-else-if="
            link.type == 'separator' &&
            !link.settings?.hidden &&
            !link.settings?.name
          "
          class="w-full my-2"
          :id="link.id || link.settings?.id"
        ></div>

        <!-- Separator with name (section header) -->
        <div
          v-else-if="
            link.type == 'separator' &&
            !link.settings?.hidden &&
            link.settings?.name
          "
          class="text-sm py-3 font-medium mt-2 rounded-lg"
          v-html="link.settings.name"
          :id="link.id"
        ></div>
      </template>
    </div>
    <div
      class="absolute bottom-0 left-0 right-0 h-32 bg-gradient-to-t from-zinc-50 to-transparent dark:from-zinc-950 pointer-events-none"
      id="uixp-menu-overlay"
    ></div>
  </div>
</template>
