<script setup>
import { ref, computed, watchEffect } from 'vue';

const loading = ref(true);
const toolbarnode = ref(null);

// get app store
import { useAppStore } from '@/store/app/app.js';
const appStore = useAppStore();

/**
 * Finds the WordPress #wp-toolbar element. Uses div#wpadminbar to ensure we get
 * the WordPress admin bar (a div), not our host container (a ul).
 */
const findWpToolbar = () => {
  // WordPress admin bar is a div; our container is a ul - use div to disambiguate
  const wpAdminBar = document.body.querySelector('div#wpadminbar');
  return wpAdminBar?.querySelector('#wp-toolbar') ?? null;
};

/**
 * Moves WordPress admin bar into custom toolbar
 */
const moveToolbar = () => {
  loading.value = true;

  if (!toolbarnode.value) {
    loading.value = false;
    return false;
  }

  const wpToolbar = findWpToolbar();
  if (!wpToolbar) {
    loading.value = false;
    return false;
  }

  // Remove unwanted items before moving the toolbar
  // Note: some items are hidden via CSS instead of removed so other components can read from them
  const itemsToRemove = [
    '#wp-admin-bar-my-account',
    '#wp-admin-bar-wp-logo',
    '#wp-admin-bar-site-name',
    '#wp-admin-bar-menu-toggle',
    '#wp-admin-bar-updates',
    '#wp-admin-bar-comments',
    // #wp-admin-bar-new-content is hidden via CSS - admin-status component reads from it
  ];

  itemsToRemove.forEach((selector) => {
    const item = wpToolbar.querySelector(selector);
    if (item) {
      item.remove();
    }
  });

  // Clear existing content and move the toolbar container into our custom toolbar
  // Only move if it's not already a child of our toolbar
  if (wpToolbar.parentNode !== toolbarnode.value) {
    toolbarnode.value.replaceChildren();
    toolbarnode.value.appendChild(wpToolbar);
  }

  loading.value = false;
  return true;
};

const returnIconOverrides = computed(() => {
  let style = '';

  const overrides = [
    ['wp-admin-bar-comments', 'chat'],
    ['wp-admin-bar-new-content', 'library_add'],
  ];

  const base = appStore.state.pluginBase;

  for (let override of overrides) {
    const iconurl = `${base}assets/icons/${override[1]}.svg`;

    style += `
	  #${override[0]} .ab-icon::before{
		content: '';
		height:1.2rem;
		width:1.2rem;
		min-height:1.2rem;
		min-width:1.2rem;
		background-color:currentColor;
		-webkit-mask: url(${iconurl}) no-repeat center;
		-webkit-mask-size: contain;
		mask: url(${iconurl}) no-repeat center;
		mask-size: contain;
		line-height: 1rem;
        display: block;
	  }`;
  }

  return style;
});

const stop = watchEffect(() => {
  if (!toolbarnode.value) return;

  // Move toolbar immediately
  const moved = moveToolbar();

  // Retry: run again after 500ms for toolbar items that load async
  setTimeout(() => {
    moveToolbar();
  }, 500);

  // If not found (e.g. panel renders before #wp-toolbar exists), retry a few times
  if (!moved) {
    [100, 300, 600].forEach((delay) => {
      setTimeout(() => moveToolbar(), delay);
    });
  }

  stop();
});
</script>

<template>
  <div class="">
    <ul
      class="flex flex-row gap-5 items-center uix-wp-admin-bar font-sans"
      ref="toolbarnode"
      id="uix-wp-toolbar-host"
    ></ul>
    <component v-if="false" is="style"> {{ returnIconOverrides }}</component>
  </div>
</template>

<style>
@reference "tailwindcss";
#wp-admin-bar-my-account,
#wp-admin-bar-wp-logo,
#wp-admin-bar-site-name,
#wp-admin-bar-new-content {
  display: none;
}
#wp-admin-bar-root-default {
  @apply flex flex-row items-center;
}

#uix-wp-toolbar-host ul[role='menu'] li a {
  @apply px-2 py-0 rounded-lg hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-all relative cursor-pointer;
}
</style>
