<script setup>
import { ref, computed, onMounted, nextTick } from 'vue';
import AppIcon from '@/components/utility/icons/index.vue';
import AppButton from '@/components/utility/app-button/index.vue';
import {
  DropdownMenu,
  DropdownMenuTrigger,
  DropdownMenuContent,
  DropdownMenuItem,
} from '@/components/ui/dropdown-menu';

const props = defineProps({
  appData: Object,
  id: String,
  className: String,
});

const postTypes = ref([]);

/**
 * Icon mapping for common post types
 */
const getPostTypeIcon = (slug) => {
  const icons = {
    post: 'article',
    page: 'description',
    media: 'image',
    user: 'account_circle',
    product: 'sell',
    shop_order: 'receipt_long',
  };
  return icons[slug] || 'description';
};

/**
 * Extract post types from WordPress admin bar
 */
const extractPostTypesFromDOM = () => {
  const newContentMenu = document.querySelector('#wp-admin-bar-new-content');
  if (!newContentMenu) return;

  const items = newContentMenu.querySelectorAll('.ab-submenu > li > a');
  const types = [];

  items.forEach((item) => {
    const href = item.getAttribute('href');
    const text = item.textContent?.trim();

    if (!href || !text) return;

    // Extract slug from the item ID or href
    const parent = item.closest('li');
    const id = parent?.id || '';
    let slug = id.replace('wp-admin-bar-new-', '');

    // Special handling for media
    if (href.includes('media-new.php')) {
      slug = 'media';
    } else if (href.includes('user-new.php')) {
      slug = 'user';
    } else if (href.includes('post-new.php')) {
      // Extract post type from URL
      const url = new URL(href, window.location.origin);
      slug = url.searchParams.get('post_type') || 'post';
    }

    types.push({
      name: slug,
      label: text,
      url: href,
      icon: getPostTypeIcon(slug),
    });
  });

  postTypes.value = types;

  newContentMenu.remove();
};

/**
 * Whether any content is available to show
 */
const hasContent = computed(() => {
  return postTypes.value.length > 0;
});

onMounted(async () => {
  await nextTick();

  extractPostTypesFromDOM();
});
</script>

<template>
  <DropdownMenu v-if="hasContent">
    <DropdownMenuTrigger as-child>
      <AppButton
        type="transparent"
        :title="__('Add New', 'uixpress')"
        :class="className"
      >
        <AppIcon icon="add" class="text-xl" />
      </AppButton>
    </DropdownMenuTrigger>

    <DropdownMenuContent
      align="start"
      :side-offset="8"
      class="w-48 p-2 gap-3 rounded-xl"
    >
      <a
        v-for="postType in postTypes"
        :key="postType.name"
        :href="postType.url"
        class="block"
      >
        <DropdownMenuItem class="cursor-pointer">
          <AppIcon
            :icon="postType.icon"
            class="text-base text-muted-foreground"
          />
          <span>{{ postType.label }}</span>
        </DropdownMenuItem>
      </a>
    </DropdownMenuContent>
  </DropdownMenu>
</template>
