<script setup>
import {
  ref,
  defineProps,
  watchEffect,
  nextTick,
  onMounted,
  onUnmounted,
} from 'vue';

const anchor = ref(null);
const props = defineProps({
  parent: {
    type: Object,
    default: null,
  },
  mouseenter: {
    type: Function,
    default: () => {},
  },
  mouseleave: {
    type: Function,
    default: () => {},
  },
  submenuBoundsChange: {
    type: Function,
    default: () => {},
  },
  submenuUnmount: {
    type: Function,
    default: () => {},
  },
});
const position = ref({});
const submenu = ref(null);

const emitBounds = () => {
  if (!submenu.value) return;
  props.submenuBoundsChange(submenu.value.getBoundingClientRect());
};

const setMenuPosition = () => {
  if (!anchor.value) return;

  const rect = anchor.value.getBoundingClientRect();
  position.value = { left: `${rect.left}px`, top: `${rect.top}px` };

  // Link submenu bounds to pointer intent after any placement updates.
  nextTick(() => {
    // Submenu is no longer visible so bail
    if (!submenu.value) return;

    const subrect = submenu.value.getBoundingClientRect();

    if (subrect.bottom > window.innerHeight) {
      position.value = {
        left: `${rect.left}px`,
        top: `${window.innerHeight - subrect.height}px`,
      };
    }

    nextTick(() => {
      emitBounds();
    });
  });
};

watchEffect(() => {
  if (anchor.value) setMenuPosition();
});

const handleViewportChange = () => {
  setMenuPosition();
};

onMounted(() => {
  window.addEventListener('resize', handleViewportChange, { passive: true });
  window.addEventListener('scroll', handleViewportChange, {
    passive: true,
    capture: true,
  });
});

onUnmounted(() => {
  window.removeEventListener('resize', handleViewportChange);
  window.removeEventListener('scroll', handleViewportChange, true);
  props.submenuUnmount();
});
</script>

<template>
  <div ref="anchor">
    <Teleport to="body">
      <div class="uixpress-isolation">
        <div
          class="uix-submenu fixed bg-white dark:bg-zinc-900 z-[9999] shadow-sm rounded-xl border border-zinc-600/10 dark:border-zinc-800 p-3 text-sm translate-x-0 uix-normalize"
          :style="position"
          @mouseenter="props.mouseenter()"
          @mouseleave="props.mouseleave()"
          ref="submenu"
        >
          <slot></slot>
        </div>
      </div>
    </Teleport>
  </div>
</template>
