const POINTER_HISTORY_LIMIT = 8;
const DEFAULT_GRACE_DELAY_MS = 160;
const DEFAULT_SUBMENU_LEAVE_DELAY_MS = 120;
const VERTICAL_GRACE_PADDING = 32;

const pointerTrail = [];
const closeTimers = new Map();
let mouseListenerAttached = false;

const clearTimer = (linkId) => {
  const timer = closeTimers.get(linkId);
  if (timer) {
    window.clearTimeout(timer);
    closeTimers.delete(linkId);
  }
};

const trackPointer = (event) => {
  pointerTrail.push({
    x: event.clientX,
    y: event.clientY,
    t: Date.now(),
  });

  if (pointerTrail.length > POINTER_HISTORY_LIMIT) {
    pointerTrail.shift();
  }
};

const ensurePointerTracking = () => {
  if (mouseListenerAttached || typeof window === 'undefined') return;

  window.addEventListener('mousemove', trackPointer, { passive: true });
  mouseListenerAttached = true;
};

const normalizeRect = (rect) => {
  if (!rect) return null;
  const { left, right, top, bottom, width, height } = rect;
  if (
    [left, right, top, bottom, width, height].some(
      (value) => Number.isNaN(value) || typeof value !== 'number'
    )
  ) {
    return null;
  }
  return { left, right, top, bottom, width, height };
};

const isMovingTowardSubmenu = (parentRect, submenuRect) => {
  const safeParentRect = normalizeRect(parentRect);
  const safeSubmenuRect = normalizeRect(submenuRect);

  if (!safeParentRect || !safeSubmenuRect || pointerTrail.length < 2) {
    return false;
  }

  const currentPoint = pointerTrail[pointerTrail.length - 1];
  const previousPoint = pointerTrail[pointerTrail.length - 2];
  const deltaX = currentPoint.x - previousPoint.x;
  const deltaY = currentPoint.y - previousPoint.y;

  if (Math.abs(deltaX) < 0.5 && Math.abs(deltaY) < 0.5) {
    return false;
  }

  const submenuIsOnRight = safeSubmenuRect.left >= safeParentRect.right;
  const submenuIsOnLeft = safeSubmenuRect.right <= safeParentRect.left;

  // Keep the logic deterministic for side-by-side menus only.
  if (!submenuIsOnRight && !submenuIsOnLeft) {
    return false;
  }

  if (submenuIsOnRight && deltaX <= 0) return false;
  if (submenuIsOnLeft && deltaX >= 0) return false;

  const edgeX = submenuIsOnRight ? safeSubmenuRect.left : safeSubmenuRect.right;
  const corridorTop =
    Math.min(safeParentRect.top, safeSubmenuRect.top) - VERTICAL_GRACE_PADDING;
  const corridorBottom =
    Math.max(safeParentRect.bottom, safeSubmenuRect.bottom) +
    VERTICAL_GRACE_PADDING;

  // If cursor is already traversing the gap toward submenu, hold open.
  const inHorizontalGap = submenuIsOnRight
    ? currentPoint.x >= safeParentRect.right && currentPoint.x <= safeSubmenuRect.left
    : currentPoint.x <= safeParentRect.left && currentPoint.x >= safeSubmenuRect.right;
  const inVerticalCorridor =
    currentPoint.y >= corridorTop && currentPoint.y <= corridorBottom;

  if (inHorizontalGap && inVerticalCorridor) {
    return true;
  }

  // Project current vector to submenu edge to infer intent.
  if (Math.abs(deltaX) < 0.5) return false;
  const projectionScale = (edgeX - currentPoint.x) / deltaX;
  if (projectionScale < 0) return false;

  const projectedY = currentPoint.y + deltaY * projectionScale;
  return projectedY >= corridorTop && projectedY <= corridorBottom;
};

const scheduleClose = (linkId, close, delay) => {
  clearTimer(linkId);
  const timer = window.setTimeout(() => {
    closeTimers.delete(linkId);
    close();
  }, delay);
  closeTimers.set(linkId, timer);
};

export function useSubmenuIntent() {
  ensurePointerTracking();

  const onParentEnter = (linkId, open) => {
    if (!linkId || typeof open !== 'function') return;
    clearTimer(linkId);
    open();
  };

  const onParentLeave = (
    linkId,
    {
      parentRect = null,
      submenuRect = null,
      closeNow,
      closeDelayed,
      delay = DEFAULT_GRACE_DELAY_MS,
    } = {}
  ) => {
    if (!linkId) return;

    const closeImmediate = typeof closeNow === 'function' ? closeNow : () => {};
    const closeWithDelay =
      typeof closeDelayed === 'function' ? closeDelayed : closeImmediate;

    const hasRects = Boolean(normalizeRect(parentRect) && normalizeRect(submenuRect));
    const useGraceDelay =
      !hasRects || isMovingTowardSubmenu(parentRect, submenuRect);

    if (useGraceDelay) {
      scheduleClose(linkId, closeWithDelay, delay);
      return;
    }

    clearTimer(linkId);
    closeImmediate();
  };

  const onSubmenuEnter = (linkId, open) => {
    if (!linkId || typeof open !== 'function') return;
    clearTimer(linkId);
    open();
  };

  const onSubmenuLeave = (
    linkId,
    { close, delay = DEFAULT_SUBMENU_LEAVE_DELAY_MS } = {}
  ) => {
    if (!linkId || typeof close !== 'function') return;
    scheduleClose(linkId, close, delay);
  };

  const clearAllIntentState = () => {
    for (const [linkId, timer] of closeTimers.entries()) {
      window.clearTimeout(timer);
      closeTimers.delete(linkId);
    }
    pointerTrail.length = 0;
  };

  const clearIntentForLink = (linkId) => {
    if (!linkId) return;
    clearTimer(linkId);
  };

  const shouldDelaySubmenuSwitch = (parentRect, submenuRect) => {
    return isMovingTowardSubmenu(parentRect, submenuRect);
  };

  return {
    onParentEnter,
    onParentLeave,
    onSubmenuEnter,
    onSubmenuLeave,
    shouldDelaySubmenuSwitch,
    clearAllIntentState,
    clearIntentForLink,
  };
}
