<script setup>
import { computed, onMounted, ref } from 'vue';
import { useAppStore } from '@/store/app/app.js';
import { lmnFetch } from '@/assets/js/functions/lmnFetch.js';
import AppIcon from '@/components/utility/icons/index.vue';

const appStore = useAppStore();
const notices = ref([]);
const loading = ref(false);
const dismissing = ref({});
const expandedNotices = ref(new Set());

const typeStyles = {
  info: {
    icon: 'info',
    wrapper:
      'border-indigo-200 bg-indigo-50 dark:bg-indigo-950/20 dark:border-indigo-800',
    title: 'text-indigo-800 dark:text-indigo-200',
    content: 'text-indigo-700 dark:text-indigo-300',
    iconColor: 'text-indigo-600 dark:text-indigo-400',
  },
  success: {
    icon: 'check_circle',
    wrapper:
      'border-green-200 bg-green-50 dark:bg-green-950/20 dark:border-green-800',
    title: 'text-green-800 dark:text-green-200',
    content: 'text-green-700 dark:text-green-300',
    iconColor: 'text-green-600 dark:text-green-400',
  },
  warning: {
    icon: 'warning',
    wrapper:
      'border-orange-200 bg-orange-50 dark:bg-orange-950/20 dark:border-orange-800',
    title: 'text-orange-800 dark:text-orange-200',
    content: 'text-orange-700 dark:text-orange-300',
    iconColor: 'text-orange-600 dark:text-orange-400',
  },
  error: {
    icon: 'error',
    wrapper: 'border-red-200 bg-red-50 dark:bg-red-950/20 dark:border-red-800',
    title: 'text-red-800 dark:text-red-200',
    content: 'text-red-700 dark:text-red-300',
    iconColor: 'text-red-600 dark:text-red-400',
  },
};

const getTypeStyle = (notice) => {
  const noticeType = notice.meta?.notice_type || 'info';
  return typeStyles[noticeType] || typeStyles.info;
};

const fetchNotices = async () => {
  loading.value = true;
  const response = await lmnFetch({
    endpoint: 'wp/v2/uixpress-notices',
    params: { status: 'publish', per_page: 100 },
  });
  loading.value = false;

  if (response?.data) {
    notices.value = response.data;
  }
};

const appliesToCurrentUser = (notice) => {
  const userId = appStore.state.userID;
  const userRoles = appStore.state.userRoles || [];
  const roles = notice.meta?.roles || [];
  const seenBy = notice.meta?.seen_by || [];

  if (seenBy.includes(Number(userId)) || seenBy.includes(userId)) return false;
  if (!roles.length) return true;
  if (roles.some((r) => r.type === 'user' && r.id == userId)) return true;
  if (roles.some((r) => r.type === 'role' && userRoles.includes(r.value)))
    return true;
  return false;
};

const importantNotices = computed(() =>
  notices.value.filter(
    (notice) => appliesToCurrentUser(notice) && notice.meta?.important === true
  )
);

const dismissNotice = async (notice) => {
  const userId = appStore.state.userID;
  if (!userId || !notice.meta?.dismissible) return;

  dismissing.value[notice.id] = true;
  const response = await lmnFetch({
    endpoint: 'uixpress/v1/notices/seen',
    type: 'POST',
    data: {
      notice_id: notice.id,
    },
  });

  if (response?.seen_by) {
    notice.meta.seen_by = response.seen_by;
  } else {
    const seenBy = Array.isArray(notice.meta?.seen_by)
      ? [...notice.meta.seen_by]
      : [];
    if (!seenBy.includes(Number(userId)) && !seenBy.includes(userId)) {
      seenBy.push(Number(userId));
    }
    notice.meta.seen_by = seenBy;
  }

  dismissing.value[notice.id] = false;
};

const toggleExpanded = (noticeId) => {
  const expanded = new Set(expandedNotices.value);
  if (expanded.has(noticeId)) {
    expanded.delete(noticeId);
  } else {
    expanded.add(noticeId);
  }
  expandedNotices.value = expanded;
};

const isLongContent = (content) => {
  const textContent = content.replace(/<[^>]*>/g, '');
  return textContent.length > 180;
};

const getTruncatedContent = (content) => {
  const textContent = content.replace(/<[^>]*>/g, '');
  if (textContent.length <= 180) return content;

  const truncated = textContent.substring(0, 180);
  const lastSpace = truncated.lastIndexOf(' ');
  const breakPoint = lastSpace > 140 ? lastSpace : 180;

  return truncated.substring(0, breakPoint) + '...';
};

onMounted(() => {
  fetchNotices();
});
</script>

<template>
  <div
    v-if="importantNotices.length > 0"
    class="uixpress-isolation px-6 pt-4 pb-2"
  >
    <div class="space-y-3 max-w-none">
      <div
        v-for="notice in importantNotices"
        :key="notice.id"
        class="border rounded-lg p-4 group"
        :class="getTypeStyle(notice).wrapper"
      >
        <div class="flex items-start gap-3">
          <AppIcon
            :icon="getTypeStyle(notice).icon"
            class="text-lg mt-0.5 flex-shrink-0"
            :class="getTypeStyle(notice).iconColor"
          />

          <div class="flex-1 min-w-0">
            <div
              class="font-medium text-sm mb-1"
              :class="getTypeStyle(notice).title"
              v-html="notice.title.rendered"
            ></div>

            <div class="text-sm" :class="getTypeStyle(notice).content">
              <div
                v-if="!isLongContent(notice.content.rendered)"
                class="prose-notice"
                v-html="notice.content.rendered"
              ></div>

              <div v-else>
                <div
                  v-if="!expandedNotices.has(notice.id)"
                  class="prose-notice"
                  v-html="getTruncatedContent(notice.content.rendered)"
                ></div>
                <div
                  v-else
                  class="prose-notice"
                  v-html="notice.content.rendered"
                ></div>

                <button
                  class="inline-flex items-center text-xs mt-1 font-medium transition-colors opacity-80 hover:opacity-100"
                  :class="getTypeStyle(notice).content"
                  @click="toggleExpanded(notice.id)"
                >
                  {{
                    expandedNotices.has(notice.id)
                      ? __('Show less', 'uixpress')
                      : __('Show more', 'uixpress')
                  }}
                </button>
              </div>
            </div>
          </div>

          <button
            v-if="notice.meta?.dismissible"
            class="text-zinc-400 hover:text-zinc-600 dark:hover:text-zinc-300 transition-colors p-1"
            :disabled="dismissing[notice.id]"
            @click="dismissNotice(notice)"
          >
            <AppIcon
              :icon="dismissing[notice.id] ? 'hourglass_empty' : 'close'"
              class="text-sm"
              :class="{ 'animate-pulse': dismissing[notice.id] }"
            />
          </button>
        </div>
      </div>
    </div>
  </div>
</template>

