import { reactive } from 'vue';

// Singleton state - shared across all imports
export const hoverStates = reactive({});
const DEFAULT_HOVER_SCOPE = 'default';

const buildHoverStateKey = (link, scope = DEFAULT_HOVER_SCOPE) => {
  if (!link?.id) return null;
  return `${scope}:${link.id}`;
};

/**
 * Sets the hover state for a menu item
 * @param {Object} link - The menu item
 * @param {boolean} state - The hover state
 * @param {string} scope - Scope key to isolate hover state by menu context
 */
export function setHoverState(link, state, scope = DEFAULT_HOVER_SCOPE) {
  const key = buildHoverStateKey(link, scope);
  if (!key) return;
  hoverStates[key] = state;
}

/**
 * Gets the hover state for a menu item
 * @param {Object} link - The menu item
 * @param {string} scope - Scope key to isolate hover state by menu context
 * @returns {boolean} The hover state
 */
export function isHovered(link, scope = DEFAULT_HOVER_SCOPE) {
  const key = buildHoverStateKey(link, scope);
  if (!key) return false;
  return hoverStates[key] || false;
}

/**
 * Clears all hover states
 * @param {string|null} scope - Optional scope to only clear related keys
 */
export function clearHoverStates(scope = null) {
  const scopePrefix = scope ? `${scope}:` : null;
  Object.keys(hoverStates).forEach((key) => {
    if (scopePrefix && !key.startsWith(scopePrefix)) return;
    delete hoverStates[key];
  });
}

/**
 * Composable for managing hover states of menu items
 * Uses singleton pattern - all components share the same state
 *
 * @returns {Object} Menu state management functions
 */
export function useHoverStates() {
  return {
    hoverStates,
    setHoverState,
    isHovered,
    clearHoverStates,
  };
}
